def estimate_precisions(self):
    identities = (
        torch.eye(self.n_features)
        .unsqueeze(0)
        .repeat(self.n_mixtures, 1, 1)
        .to(self.device)
    )
    L = torch.cholesky(self.sigma, upper=False)
